// EP-70: finite proxy hypergraph coloring (Ramsey-type) on 3-uniform edges.
{
  function largestHomogeneous(n, colors) {
    // colors indexed by triple (i,j,k) with i<j<k, flattened by combinadic index.
    function idx(i, j, k) {
      let c = 0;
      for (let a = 0; a < i; a += 1) c += (n - a - 1) * (n - a - 2) / 2;
      for (let b = i + 1; b < j; b += 1) c += (n - b - 1);
      c += k - j - 1;
      return c | 0;
    }

    let best = 0;
    const total = 1 << n;
    for (let mask = 1; mask < total; mask += 1) {
      const verts = [];
      for (let i = 0; i < n; i += 1) if ((mask >> i) & 1) verts.push(i);
      if (verts.length <= best) continue;
      if (verts.length < 3) {
        if (verts.length > best) best = verts.length;
        continue;
      }
      let color = -1;
      let ok = true;
      for (let i = 0; i < verts.length && ok; i += 1) {
        for (let j = i + 1; j < verts.length && ok; j += 1) {
          for (let k = j + 1; k < verts.length; k += 1) {
            const c = colors[idx(verts[i], verts[j], verts[k])];
            if (color === -1) color = c;
            else if (c !== color) {
              ok = false;
              break;
            }
          }
        }
      }
      if (ok) best = verts.length;
    }
    return best;
  }

  function optimize(n, iters, seed) {
    const rng = makeRng(seed);
    const m = (n * (n - 1) * (n - 2)) / 6;
    const colors = new Uint8Array(m);
    for (let i = 0; i < m; i += 1) colors[i] = rng() < 0.5 ? 0 : 1;
    let best = largestHomogeneous(n, colors);
    for (let t = 0; t < iters; t += 1) {
      const idx = Math.floor(rng() * m);
      colors[idx] ^= 1;
      const cur = largestHomogeneous(n, colors);
      if (cur <= best || rng() < Math.exp((best - cur) / 2)) {
        best = Math.min(best, cur);
      } else {
        colors[idx] ^= 1;
      }
    }
    return best;
  }

  const rows = [];
  for (const n of [8, 9, 10]) {
    let best = Infinity;
    for (let r = 0; r < 6; r += 1) {
      const v = optimize(n, 400, 20260304 ^ (n * 31 + r));
      if (v < best) best = v;
    }
    rows.push({ n, best_min_homogeneous_size: best });
  }

  out.results.ep70 = {
    description: 'Finite 3-uniform hypergraph coloring proxy: minimize largest homogeneous subset size.',
    rows,
  };
}
